Sure! Here’s a simple test code for the ESP32 that will connect to a Wi-Fi network and print the IP address:

```cpp
#include <WiFi.h>

const char* ssid = "your_SSID";     // Replace with your network SSID
const char* password = "your_PASSWORD"; // Replace with your network password

void setup() {
  Serial.begin(115200);
  WiFi.begin(ssid, password);

  while (WiFi.status() != WL_CONNECTED) {
    delay(1000);
    Serial.println("Connecting to WiFi...");
  }

  Serial.println("Connected to WiFi!");
  Serial.print("IP Address: ");
  Serial.println(WiFi.localIP());
}

void loop() {
  // Nothing to do here
}
```

Replace `your_SSID` and `your_PASSWORD` with your actual Wi-Fi credentials. Let me know if you need more details!
